import{_ as t,o as a,c as r,a2 as o}from"./chunks/framework.DeNJmwJc.js";const u=JSON.parse('{"title":"Chapter 32 ‚Äî Regex in Vim","description":"","frontmatter":{},"headers":[],"relativePath":"chapters/32-regex.md","filePath":"chapters/32-regex.md"}'),i={name:"chapters/32-regex.md"};function d(s,e,c,n,l,h){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="chapter-32-‚Äî-regex-in-vim" tabindex="-1">Chapter 32 ‚Äî Regex in Vim <a class="header-anchor" href="#chapter-32-‚Äî-regex-in-vim" aria-label="Permalink to &quot;Chapter 32 ‚Äî Regex in Vim&quot;">‚Äã</a></h1><blockquote><p><em>&quot;Regular expressions turn search into a superpower.&quot;</em></p></blockquote><hr><p><strong>Difficulty:</strong> ‚≠ê‚≠ê‚≠ê‚≠ê Advanced <strong>Estimated Reading Time:</strong> 20 minutes</p><hr><h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">‚Äã</a></h1><p>Vim has its own regex syntax, similar but not identical to Perl/PCRE.</p><hr><h1 id="vim-magic-levels" tabindex="-1">Vim Magic Levels <a class="header-anchor" href="#vim-magic-levels" aria-label="Permalink to &quot;Vim Magic Levels&quot;">‚Äã</a></h1><table tabindex="0"><thead><tr><th>Mode</th><th>Prefix</th><th>Example</th></tr></thead><tbody><tr><td>Magic</td><td><code>\\v</code></td><td>`/\\v(abc</td></tr><tr><td>Nomagic</td><td><code>\\V</code></td><td><code>/\\Vfoo.bar</code> (literal)</td></tr><tr><td>Very magic</td><td><code>\\v</code></td><td>`/\\v(a</td></tr></tbody></table><h2 id="very-magic-v" tabindex="-1">Very Magic (<code>\\v</code>) <a class="header-anchor" href="#very-magic-v" aria-label="Permalink to &quot;Very Magic (`\\v`)&quot;">‚Äã</a></h2><p>Disables escaping for most special characters.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/\\v(abc|def){2,3}</span></span></code></pre></div><h2 id="very-nomagic-v" tabindex="-1">Very Nomagic (<code>\\V</code>) <a class="header-anchor" href="#very-nomagic-v" aria-label="Permalink to &quot;Very Nomagic (`\\V`)&quot;">‚Äã</a></h2><p>Treats everything literally except <code>\\</code>.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/\\Vfoo.bar   ‚Üí   matches &quot;foo.bar&quot; literally</span></span></code></pre></div><hr><h1 id="regex-examples" tabindex="-1">Regex Examples <a class="header-anchor" href="#regex-examples" aria-label="Permalink to &quot;Regex Examples&quot;">‚Äã</a></h1><table tabindex="0"><thead><tr><th>Pattern</th><th>Matches</th></tr></thead><tbody><tr><td><code>/\\vfoo|bar</code></td><td><code>foo</code> or <code>bar</code></td></tr><tr><td><code>/\\v(colou)?r</code></td><td><code>color</code> or <code>colour</code></td></tr><tr><td><code>/\\v\\d+</code></td><td>One or more digits</td></tr><tr><td><code>/\\v\\w+@\\w+\\.\\w+</code></td><td>Simple email pattern</td></tr></tbody></table><hr><h1 id="regex-in-substitution" tabindex="-1">Regex in Substitution <a class="header-anchor" href="#regex-in-substitution" aria-label="Permalink to &quot;Regex in Substitution&quot;">‚Äã</a></h1><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>:%s/\\v(\\w+)@(\\w+)/\\1 at \\2/g</span></span></code></pre></div><p>Replace <code>user@domain</code> with <code>user at domain</code>.</p><hr><h1 id="chapter-summary" tabindex="-1">Chapter Summary <a class="header-anchor" href="#chapter-summary" aria-label="Permalink to &quot;Chapter Summary&quot;">‚Äã</a></h1><ul><li>Vim uses its own regex syntax.</li><li><code>\\v</code> enables &quot;very magic&quot; (less escaping).</li><li><code>\\V</code> disables special characters.</li><li>Regex works in both search and substitution.</li></ul><hr><h2 id="next-chapter" tabindex="-1">Next Chapter <a class="header-anchor" href="#next-chapter" aria-label="Permalink to &quot;Next Chapter&quot;">‚Äã</a></h2><p><a href="./33-search-history.html"><strong>Chapter 33 ‚Äî Search History</strong></a></p><p>Navigate your search history like a pro.</p>',30)])])}const m=t(i,[["render",d]]);export{u as __pageData,m as default};
